part of '../view.dart';class HomeTabBar extends StatelessWidget implements PreferredSizeWidget {  const HomeTabBar({super.key, required this.controller});  final TabController controller;  @override  Widget build(BuildContext context) {    return TabBar(      controller: controller,      indicatorColor: AppColors.primary,      indicatorWeight: 3,      dividerColor: AppColors.gray,      dividerHeight: 30,      overlayColor: const WidgetStatePropertyAll(Colors.transparent),      tabs: [        AppTabIcon(          asset: AppIcons.home,          selected: controller.index == 0,          width: 23,          height: 25,        ),        AppTabIcon(          asset: AppIcons.videos,          selected: controller.index == 1,          width: 30,          height: 25,        ),        AppTabIcon(          asset: AppIcons.store,          selected: controller.index == 2,          width: 26,          height: 26,        ),        AppTabIcon(          asset: AppIcons.profile,          selected: controller.index == 3,          width: 26,          height: 26,        ),        AppTabIcon(          asset: AppIcons.bell,          selected: controller.index == 4,          width: 26,          height: 26,        ),        Tab(          icon: Container(              clipBehavior: .hardEdge,              decoration: BoxDecoration(shape: BoxShape.circle),              child: Image.network(                'https://imageio.forbes.com/specials-images/imageserve/663e595b4509f97fdafb95f5/0x0.jpg?format=jpg&crop=383,383,x1045,y23,safe&height=416&width=416&fit=bounds',                fit: BoxFit.cover,                width: 30,                height: 30,              ),            ),        ),      ],    );  }  @override  Size get preferredSize => const Size.fromHeight(48);}